1	// src/components/PriceLookup.jsx
2	import React, { useState } from "react";
3	import {
4	  getTriggerMinuteCandles,
5	  getRangeHighLow,
6	  getLastPriceAtSecond,
7	  findPriceOccurrences,
8	  checkTrailingStop, // ✅ Added
9	} from "../pricing";
10	
11	import { useApp } from "../context/AppContext";
12	
13	export default function PriceLookup({ lang, uiStrings }) {
14	  const { activeSymbol, setActiveSymbol } = useApp();
15	  const [market, setMarket] = useState("futures"); // "futures" | "spot"
16	  const [mode, setMode] = useState("trigger"); // "trigger" | "range" | "last1s" | "findPrice"
17	  const [priceType, setPriceType] = useState("last"); // "last" | "mark"
18	  const [at, setAt] = useState("");
19	  const [from, setFrom] = useState("");
20	  const [to, setTo] = useState("");
21	  const [targetPrice, setTargetPrice] = useState(""); // ✅ New Input
22	  const [activationPrice, setActivationPrice] = useState(""); // ✅ Trailing Stop
23	  const [callbackRate, setCallbackRate] = useState(""); // ✅ Trailing Stop
24	  const [direction, setDirection] = useState("short"); // "short" | "long"
25	  const [result, setResult] = useState("");
26	  const [error, setError] = useState("");
27	
28	  const t = uiStrings; // Çeviri metinleri
29	
30	  const setPresentTime = () => {
31	    const now = new Date();
32	    // 1 minute ago UTC
33	    const past = new Date(now.getTime() - 60 * 1000);
34	    const pad = (n) => String(n).padStart(2, '0');
35	    const formatted = `${past.getUTCFullYear()}-${pad(past.getUTCMonth() + 1)}-${pad(past.getUTCDate())} ${pad(past.getUTCHours())}:${pad(past.getUTCMinutes())}:00`;
36	    setTo(formatted);
37	  };
38	
39	  async function handleLookup() {
40	    setResult("");
41	    setError("");
42	    const errTime = lang === 'tr' ? 'Lütfen bir "Tetiklenme Zamanı" girin.' : 'Please enter a Triggered At timestamp.';
43	    const errRange = lang === 'tr' ? 'Lütfen Başlangıç ve Bitiş zamanlarını girin.' : 'Please enter both From and To.';
44	    const errPrice = lang === 'tr' ? 'Lütfen bir hedef Fiyat girin.' : 'Please enter a target Price.';
45	    const errLast1s = lang === 'tr' ? 'Lütfen bir Tarih/Zaman (UTC) girin.' : 'Please enter a DateTime (UTC).';
46	    const errCallback = lang === 'tr' ? 'Lütfen Geri Dönüş Oranı girin.' : 'Please enter Callback Rate.';
47	
48	    try {
49	      if (mode === "trigger") {
50	        if (!at) return setError(errTime);
51	        const { mark, last } = await getTriggerMinuteCandles(activeSymbol, at, market);
52	
53	        if (!mark && !last) return setResult(t.lookupNotFound);
54	
55	        let msg = `### 🕒 ${at} UTC+0\n` +
56	          `**Symbol:** ${activeSymbol} | **Market:** ${market.toUpperCase()}\n\n` +
57	          (lang === 'tr' ? `#### Fiyat Verileri:` : `#### Price Data:`) + `\n\n`;
58	
59	        if (market === "futures") {
60	          msg += `> **Mark Price:**\n` +
61	            `> - ` + (lang === 'tr' ? `Açılış` : `Open`) + `: ${mark?.open ?? "N/A"}\n` +
62	            `> - ` + (lang === 'tr' ? `Yüksek` : `High`) + `: ${mark?.high ?? "N/A"}\n` +
63	            `> - ` + (lang === 'tr' ? `Düşük` : `Low`) + `: ${mark?.low ?? "N/A"}\n` +
64	            `> - ` + (lang === 'tr' ? `Kapanış` : `Close`) + `: ${mark?.close ?? "N/A"}\n\n`;
65	        }
66	
67	        msg += `> **Last Price:**\n` +
68	          `> - ` + (lang === 'tr' ? `Açılış` : `Open`) + `: ${last?.open ?? "N/A"}\n` +
69	          `> - ` + (lang === 'tr' ? `Yüksek` : `High`) + `: ${last?.high ?? "N/A"}\n` +
70	          `> - ` + (lang === 'tr' ? `Düşük` : `Low`) + `: ${last?.low ?? "N/A"}\n` +
71	          `> - ` + (lang === 'tr' ? `Kapanış` : `Close`) + `: ${last?.close ?? "N/A"}`;
72	
73	        setResult(msg);
74	
75	      } else if (mode === "range") {
76	        if (!from || !to) return setError(errRange);
77	        const range = await getRangeHighLow(activeSymbol, from, to, market);
78	        if (!range) return setResult(t.lookupNotFound);
79	
80	        let msg = `### 📊 ` + (lang === 'tr' ? `Aralık Özeti` : `Range Summary`) + `\n` +
81	          `**Symbol:** ${activeSymbol} | **Market:** ${market.toUpperCase()}\n` +
82	          `**Period:** ${from} → ${to}\n\n` +
83	          (lang === 'tr' ? `#### Analiz Sonuçları:` : `#### Analysis Results:`) + `\n\n`;
84	
85	        if (market === "futures") {
86	          msg += `✅ **Mark Price:**\n` +
87	            `- ` + (lang === 'tr' ? `Zirve` : `Peak`) + `: ${range.mark.high} (${range.mark.highTime})\n` +
88	            `- ` + (lang === 'tr' ? `Dip` : `Bottom`) + `: ${range.mark.low} (${range.mark.lowTime})\n` +
89	            `- ` + (lang === 'tr' ? `Değişim` : `Volatility`) + `: ${range.mark.changePct}\n\n`;
90	        }
91	
92	        msg += `✅ **Last Price:**\n` +
93	          `- ` + (lang === 'tr' ? `Zirve` : `Peak`) + `: ${range.last.high} (${range.last.highTime})\n` +
94	          `- ` + (lang === 'tr' ? `Dip` : `Bottom`) + `: ${range.last.low} (${range.last.lowTime})\n` +
95	          `- ` + (lang === 'tr' ? `Değişim` : `Volatility`) + `: ${range.last.changePct}`;
96	
97	        setResult(msg);
98	
99	      } else if (mode === "last1s") {
100	        if (!at) return setError(errLast1s);
101	        const ohlc = await getLastPriceAtSecond(activeSymbol, at, market);
102	        if (!ohlc) return setResult(t.lookupNoTradeData);
103	
104	        const msg = `### ⚡ ` + (lang === 'tr' ? `Saniyelik Hassasiyet` : `Second Precision`) + `\n` +
105	          `**Time:** ${at} UTC+0 (${market.toUpperCase()})\n\n` +
106	          `> **Last Price Details:**\n` +
107	          `> - ` + (lang === 'tr' ? `Açılış` : `Open`) + `: ${ohlc.open}\n` +
108	          `> - ` + (lang === 'tr' ? `Yüksek` : `High`) + `: ${ohlc.high}\n` +
109	          `> - ` + (lang === 'tr' ? `Düşük` : `Low`) + `: ${ohlc.low}\n` +
110	          `> - ` + (lang === 'tr' ? `Kapanış` : `Close`) + `: ${ohlc.close}\n\n` +
111	          `ℹ️ ` + (lang === 'tr' ? `Bu veri o saniye içindeki **${ohlc.count}** işleme dayanmaktadır.` : `Derived from **${ohlc.count}** individual trades in this second.`);
112	        setResult(msg);
113	
114	      } else if (mode === "findPrice") {
115	        if (!from || !to) return setError(errRange);
116	        if (!targetPrice) return setError(errPrice);
117	
118	        const finalType = (market === 'futures') ? priceType : 'last';
119	        const data = await findPriceOccurrences(activeSymbol, from, to, parseFloat(targetPrice), market, finalType);
120	
121	        if (!data || !data.first) {
122	          const noReachMsg = t.lookupPriceNotReached.replace("{price}", targetPrice);
123	          return setResult(`${t.lookupNotFoundTitle}\n\n${noReachMsg}`);
124	        }
125	
126	        const typeLabel = finalType === 'mark' ? 'Mark Price' : 'Last Price';
127	        let msg = `## ${t.lookupFoundTitle}\n\n` +
128	          `**Symbol:** ${activeSymbol} (${market.toUpperCase()})\n` +
129	          `**Target:** ${targetPrice} (${typeLabel})\n` +
130	          `**Search Period:** ${from} → ${to}\n\n` +
131	          `--- \n\n` +
132	          `✅ **` + (lang === 'tr' ? `İLK TEMAS ZAMANI` : `FIRST CONTACT TIME`) + `:**\n` +
133	          `### 🕒 ${data.first.fmt} UTC+0\n` +
134	          (data.first.isExact ? (lang === 'tr' ? `(🛡️ İşlem verileriyle milisaniye bazında doğrulandı)` : `(🛡️ Verified at millisecond level via AggTrades)`) : (lang === 'tr' ? `(📊 1 dakikalık mum verisiyle tespit edildi)` : `(📊 Detected via 1m Candle data)`)) + `\n\n`;
135	
136	        if (data.others.length > 0) {
137	          msg += `🔄 **` + (lang === 'tr' ? `DİĞER EŞLEŞMELER` : `OTHER MATCHES`) + ` (` + (lang === 'tr' ? `Yaklaşık` : `Approx`) + `):**\n`;
138	          const limit = 10;
139	          data.others.slice(0, limit).forEach(tMatch => {
140	            msg += `- ${tMatch} UTC+0\n`;
141	          });
142	          if (data.others.length > limit) {
143	            msg += `\n*...` + (lang === 'tr' ? `ve ${data.others.length - limit} kez daha.` : `and ${data.others.length - limit} more instances.*`);
144	          }
145	        }
146	        setResult(msg);
147	
148	      } else if (mode === "trailing") {
149	        if (!from || !to) return setError(errRange);
150	        if (!callbackRate) return setError(errCallback);
151	        if (!activationPrice) return setError(lang === 'tr' ? 'Lütfen Aktivasyon Fiyatı girin.' : 'Please enter Activation Price.');
152	
153	        const actPrice = parseFloat(activationPrice);
154	        const cbRate = parseFloat(callbackRate);
155	        const finalType = (market === 'futures') ? priceType : 'last';
156	        const sTrim = activeSymbol.trim();
157	        const fTrim = from.trim();
158	        const tTrim = to.trim();
159	
160	        const data = await checkTrailingStop(sTrim, fTrim, tTrim, actPrice, cbRate, direction, market, finalType);
161	
162	        if (data.status === "not_found") {
163	          return setResult(`${t.lookupNotFound}\n\nDEBUG: Symbol: ${sTrim}, From: ${fTrim}, To: ${tTrim}, Market: ${market}`);
164	        }
165	
166	        let msg = `## ${data.status === 'triggered' ? t.trailingTriggeredTitle : t.trailingNotTriggeredTitle}\n\n`;
167	
168	        if (data.isActivated) {
169	          // STEP 1: Activation
170	          msg += `### ${t.trailingResultActivated}\n` +
171	            `> ${t.trailingStep1Desc}\n` +
172	            `> 🕒 **${data.activationTime || from}**\n\n`;
173	
174	          // STEP 2: Peak/Bottom Tracking
175	          msg += `### ${direction === 'short' ? t.trailingResultPeakLabel : t.trailingResultTroughLabel}\n` +
176	            `> **${lang === 'tr' ? 'Referans Noktası' : 'Reference Point'}:** ${t.trailingStep2Desc}\n` +
177	            `> 💎 **${data.peakPrice}** (🕒 ${data.peakTime})\n\n`;
178	
179	          const rbRate = data.maxObservedCallback || 0;
180	          const currentTrigger = direction === 'short'
181	            ? (data.peakPrice * (1 - cbRate / 100)).toFixed(5)
182	            : (data.peakPrice * (1 + cbRate / 100)).toFixed(5);
183	
184	          // STEP 3: Trigger or Waiting
185	          if (data.status === "triggered") {
186	            msg += `### ${t.trailingResultTrigger}\n` +
187	              `> ${direction === 'short'
188	                ? (lang === 'tr' ? 'Fiyat zirveden yeterince geri çekilerek emri tetikledi.' : 'The price pulled back from the peak enough to trigger.')
189	                : (lang === 'tr' ? 'Fiyat alttan (Bottom) yeterince sıçrayarak emri tetikledi.' : 'The price bounced up from the bottom enough to trigger.')}\n` +
190	              `> 🕒 **${data.triggerTime}**\n` +
191	              `> 💵 Triggered at: **${data.triggerPrice?.toFixed(5)}**\n\n`;
192	          } else {
193	            msg += `### ${t.trailingResultTrigger}\n` +
194	              `> ${t.trailingStepNoTriggerDesc}\n\n` +
195	              `> 💡 **${t.trailingNextTriggerTip}: ${currentTrigger}**\n\n`;
196	          }
197	
198	          // AGENT SUMMARY (SCRIBABLE FOR CUSTOMER)
199	          msg += `--- \n` +
200	            `### ${t.trailingAgentSummary}\n` +
201	            `> ${lang === 'tr'
202	              ? `Emriniz **${data.activationTime || from}** tarihinde aktifleşti. Aktivasyondan sonra fiyatın ulaştığı ${direction === 'short' ? 'en yüksek nokta (Peak)' : 'en düşük nokta (Bottom)'} **${data.peakPrice}** oldu. Emrin tetiklenmesi için fiyatın bu noktadan **${cbRate}%** ${direction === 'short' ? 'geri çekilerek' : 'yukarı sıçrayarak'} **${currentTrigger}** seviyesine ulaşması gerekiyordu. ` +
203	              (data.status === 'triggered'
204	                ? `Fiyat bu seviyeye **${data.triggerTime}** tarihinde ulaştı ve tetiklendi.`
205	                : `Fiyat şu ana kadar en fazla **%${rbRate.toFixed(2)}** ${direction === 'short' ? 'geri çekildi' : 'yukarı sıçradı'}, bu yüzden henüz tetiklenmedi.`)
206	              : `Your order was activated at **${data.activationTime || from}**. After activation, the price reached its ${direction === 'short' ? 'highest point (Peak)' : 'lowest point (Bottom)'} at **${data.peakPrice}**. To trigger, the price needed to move **${cbRate}%** ${direction === 'short' ? 'down' : 'up'} from that point to reach **${currentTrigger}**. ` +
207	              (data.status === 'triggered'
208	                ? `The price reached this level at **${data.triggerTime}** and triggered.`
209	                : `The price has only ${direction === 'short' ? 'pulled back' : 'rebounded'} **${rbRate.toFixed(2)}%** so far, which is why it hasn't triggered yet.`)}\n\n`;
210	
211	          // TECHNICAL BREAKDOWN
212	          msg += `--- \n` +
213	            `📝 **${t.trailingReboundFormula}**\n` +
214	            `> • ${direction === 'short' ? t.trailingPullback : t.trailingRebound}: **${rbRate.toFixed(2)}%**\n` +
215	            `> • ${lang === 'tr' ? 'Hedef' : 'Target'}: **${cbRate}%** \n` +
216	            `> *(${direction === 'short' ? lang === 'tr' ? '(Zirve - En Düşük) / Zirve' : '(Peak - Bottom) / Peak' : lang === 'tr' ? '(En Yüksek - Dip) / Dip' : '(Rebound - Trough) / Trough'} = ${rbRate.toFixed(2)}%)*\n\n` +
217	            `**${t.trailingAgentInternalTitle}:**\n` +
218	            `> *${direction === 'short' ? t.trailingAgentInternalDescShort : t.trailingAgentInternalDescLong}*` +
219	            (data.isEstimated ? `\n\n${t.trailingEstimatedNotice}` : "");
