// Binance Margin Restricted Asset helper
//
// Endpoint: GET /sapi/v1/margin/restricted-asset  (MARKET_DATA — requires X-MBX-APIKEY header only)
// Docs: https://developers.binance.com/docs/margin_trading/market-data/Get-Margin-Restricted-Assets
//
// The API key is stored in localStorage (client-entered) so it is NOT baked into the
// GitHub Pages deployment. Each agent enters their own key once.

const LS_KEY = "binance_api_key_v1";
const CACHE_KEY = "margin_restricted_cache_v1";
const HISTORY_KEY = "margin_restricted_history_v1";
const CACHE_TTL_MS = 60_000; // 60s — refresh limit to be friendly to rate limits

const SAPI_BASES = [
  "https://api.binance.com",
  "https://api1.binance.com",
  "https://api2.binance.com",
  "https://api3.binance.com",
];

export type RestrictedPayload = {
  openLongRestrictedAsset: string[];
  maxCollateralExceededAsset: string[];
};

export type CachedPayload = RestrictedPayload & { fetchedAt: number };

export type HistoryEntry = {
  ts: number;
  added: { openLong: string[]; maxCollateral: string[] };
  removed: { openLong: string[]; maxCollateral: string[] };
};

export function getApiKey(): string {
  try {
    return localStorage.getItem(LS_KEY) || "";
  } catch {
    return "";
  }
}

export function setApiKey(key: string): void {
  try {
    if (key) localStorage.setItem(LS_KEY, key.trim());
    else localStorage.removeItem(LS_KEY);
  } catch {
    /* ignore */
  }
}

export function clearApiKey(): void {
  setApiKey("");
}

function readCache(): CachedPayload | null {
  try {
    const raw = localStorage.getItem(CACHE_KEY);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as CachedPayload;
    if (!parsed || typeof parsed.fetchedAt !== "number") return null;
    return parsed;
  } catch {
    return null;
  }
}

function writeCache(data: CachedPayload): void {
  try {
    localStorage.setItem(CACHE_KEY, JSON.stringify(data));
  } catch {
    /* ignore */
  }
}

function readHistory(): HistoryEntry[] {
  try {
    const raw = localStorage.getItem(HISTORY_KEY);
    if (!raw) return [];
    return JSON.parse(raw) as HistoryEntry[];
  } catch {
    return [];
  }
}

function writeHistory(list: HistoryEntry[]): void {
  try {
    // cap at 50 entries
    const trimmed = list.slice(-50);
    localStorage.setItem(HISTORY_KEY, JSON.stringify(trimmed));
  } catch {
    /* ignore */
  }
}

function diff(prev: string[], next: string[]): { added: string[]; removed: string[] } {
  const p = new Set(prev);
  const n = new Set(next);
  return {
    added: next.filter(a => !p.has(a)),
    removed: prev.filter(a => !n.has(a)),
  };
}

async function fetchOnce(base: string, apiKey: string, signal?: AbortSignal): Promise<RestrictedPayload> {
  const url = `${base}/sapi/v1/margin/restricted-asset`;
  const res = await fetch(url, {
    method: "GET",
    headers: { "X-MBX-APIKEY": apiKey },
    signal,
  });
  if (!res.ok) {
    const text = await res.text().catch(() => "");
    throw new Error(`HTTP ${res.status}${text ? ` — ${text.slice(0, 200)}` : ""}`);
  }
  const data = await res.json();
  return {
    openLongRestrictedAsset: Array.isArray(data?.openLongRestrictedAsset) ? data.openLongRestrictedAsset : [],
    maxCollateralExceededAsset: Array.isArray(data?.maxCollateralExceededAsset) ? data.maxCollateralExceededAsset : [],
  };
}

export async function fetchRestricted(opts?: { force?: boolean }): Promise<CachedPayload> {
  const cached = readCache();
  if (!opts?.force && cached && Date.now() - cached.fetchedAt < CACHE_TTL_MS) {
    return cached;
  }

  const key = getApiKey();
  if (!key) throw new Error("MISSING_API_KEY");

  let lastErr: unknown = null;
  for (const base of SAPI_BASES) {
    try {
      const data = await fetchOnce(base, key);
      const fresh: CachedPayload = { ...data, fetchedAt: Date.now() };

      // history diff
      if (cached) {
        const oL = diff(cached.openLongRestrictedAsset, fresh.openLongRestrictedAsset);
        const oC = diff(cached.maxCollateralExceededAsset, fresh.maxCollateralExceededAsset);
        if (oL.added.length || oL.removed.length || oC.added.length || oC.removed.length) {
          const hist = readHistory();
          hist.push({
            ts: fresh.fetchedAt,
            added: { openLong: oL.added, maxCollateral: oC.added },
            removed: { openLong: oL.removed, maxCollateral: oC.removed },
          });
          writeHistory(hist);
        }
      }

      writeCache(fresh);
      return fresh;
    } catch (e) {
      lastErr = e;
    }
  }
  throw lastErr instanceof Error ? lastErr : new Error("Failed to fetch from all Binance SAPI hosts");
}

export function getHistory(): HistoryEntry[] {
  return readHistory();
}

export function getCached(): CachedPayload | null {
  return readCache();
}

// ----- Diagnostics -----

export type ActionType = "long" | "short" | "borrow";

export type Diagnosis = {
  verdict: "blocked" | "clear" | "unknown";
  reasonCode: "OPEN_LONG_RESTRICTED" | "MAX_COLLATERAL_EXCEEDED_QUOTE" | "MAX_COLLATERAL_EXCEEDED_BASE" | "NONE" | "MISSING_PAIR";
  base?: string;
  quote?: string;
  action: ActionType;
  plainEnglish: string;
  customerReply: string;
  faqUrl: string;
};

const FAQ_URL = "https://www.binance.com/en/support/faq/detail/dca77ef963294b368b5ebad0affeda09";

// Split a pair like "CHZ/USDC", "CHZUSDC", "CHZ-USDC" into base/quote.
// We try common quote suffixes when there's no separator.
const COMMON_QUOTES = ["USDT", "USDC", "FDUSD", "BUSD", "TUSD", "DAI", "BTC", "ETH", "BNB", "TRY", "EUR", "USDP", "DAI"];
export function parsePair(pair: string): { base: string; quote: string } | null {
  if (!pair) return null;
  const p = pair.trim().toUpperCase();
  const m = p.match(/^([A-Z0-9]+)[\/\-_ ]([A-Z0-9]+)$/);
  if (m) return { base: m[1], quote: m[2] };
  // try suffix match
  for (const q of COMMON_QUOTES) {
    if (p.endsWith(q) && p.length > q.length) {
      return { base: p.slice(0, p.length - q.length), quote: q };
    }
  }
  return null;
}

export function diagnosePair(
  pair: string,
  action: ActionType,
  data: RestrictedPayload,
): Diagnosis {
  const parts = parsePair(pair);
  if (!parts) {
    return {
      verdict: "unknown",
      reasonCode: "MISSING_PAIR",
      action,
      plainEnglish: "Could not parse the trading pair. Use formats like CHZ/USDC, CHZ-USDC, or CHZUSDC.",
      customerReply: "",
      faqUrl: FAQ_URL,
    };
  }
  const { base, quote } = parts;
  const longList = new Set(data.openLongRestrictedAsset);
  const collatList = new Set(data.maxCollateralExceededAsset);

  if (action === "long" && longList.has(base)) {
    return {
      verdict: "blocked",
      reasonCode: "OPEN_LONG_RESTRICTED",
      base,
      quote,
      action,
      plainEnglish: `${base} is currently on Binance's open-long restricted list. New long margin positions on any ${base} pair are blocked platform-wide until Binance lifts the restriction.`,
      customerReply:
        `Thanks for reaching out. The reason you can't open a long position on ${base}/${quote} in margin is that ${base} is currently on Binance's open-long restricted asset list. This is a platform-wide restriction, not specific to your account — it applies to all users until the cap is lifted. More info: ${FAQ_URL}. You can either wait for the restriction to be removed, or consider other trading pairs.`,
      faqUrl: FAQ_URL,
    };
  }

  if (action === "short" && collatList.has(quote)) {
    return {
      verdict: "blocked",
      reasonCode: "MAX_COLLATERAL_EXCEEDED_QUOTE",
      base,
      quote,
      action,
      plainEnglish: `${quote} has reached Binance's max collateral threshold. Using ${quote} as collateral to open a new short on ${base}/${quote} is blocked until the cap frees up.`,
      customerReply:
        `Thanks for reaching out. The reason you can't open a short position on ${base}/${quote} in margin is that ${quote} has reached Binance's maximum collateral threshold. This is a platform-wide cap, not specific to your account. You have a few options: (1) try a different quote asset (e.g. USDT instead of ${quote}), (2) reduce your ${quote} collateral, or (3) wait for the cap to free up. More info: ${FAQ_URL}.`,
      faqUrl: FAQ_URL,
    };
  }

  if (action === "short" && collatList.has(base)) {
    return {
      verdict: "blocked",
      reasonCode: "MAX_COLLATERAL_EXCEEDED_BASE",
      base,
      quote,
      action,
      plainEnglish: `${base} has reached Binance's max collateral threshold, which can cap borrow availability needed to open a short on ${base}/${quote}.`,
      customerReply:
        `Thanks for reaching out. ${base} has currently reached Binance's maximum collateral threshold, which can limit borrow availability needed to open a short on ${base}/${quote}. This is a platform-wide cap. Options: wait for the cap to lift, or try a different pair. More info: ${FAQ_URL}.`,
      faqUrl: FAQ_URL,
    };
  }

  if (action === "borrow" && (collatList.has(base) || collatList.has(quote))) {
    const blocked = collatList.has(base) ? base : quote;
    return {
      verdict: "blocked",
      reasonCode: blocked === base ? "MAX_COLLATERAL_EXCEEDED_BASE" : "MAX_COLLATERAL_EXCEEDED_QUOTE",
      base,
      quote,
      action,
      plainEnglish: `${blocked} has exceeded its max collateral threshold — borrowing is currently limited.`,
      customerReply:
        `${blocked} is currently at Binance's maximum collateral cap, so borrow requests involving ${blocked} are limited. This is platform-wide. More info: ${FAQ_URL}.`,
      faqUrl: FAQ_URL,
    };
  }

  return {
    verdict: "clear",
    reasonCode: "NONE",
    base,
    quote,
    action,
    plainEnglish:
      `No platform-wide margin restriction detected for ${base}/${quote} on this action. If the user still can't ${action}, check account-specific causes: isolated balance, risk/VIP tier, asset delisting, or scheduled maintenance.`,
    customerReply: "",
    faqUrl: FAQ_URL,
  };
}

// ----- Single-asset lookup -----

export type AssetStatus = {
  asset: string;
  openLongRestricted: boolean;
  maxCollateralExceeded: boolean;
};

export function lookupAsset(asset: string, data: RestrictedPayload): AssetStatus {
  const a = asset.trim().toUpperCase();
  return {
    asset: a,
    openLongRestricted: data.openLongRestrictedAsset.includes(a),
    maxCollateralExceeded: data.maxCollateralExceededAsset.includes(a),
  };
}

