                    </div>
                  </>
                )}
                {!diagnosis.customerReply && diagnosis.verdict === "clear" && (
                  <div style={{ fontSize: 12, color: "#9aa4b2" }}>
                    {isTr
                      ? "Platform seviyesinde bir engel yok. Kullanıcıya özgü sebepleri (izole bakiye, risk/VIP seviyesi, bakım, listeden çıkarma) kontrol edin."
                      : "No platform block. Check account-specific causes: isolated balance, risk/VIP tier, maintenance, or delisting."}
