              className="input"
              placeholder="CHZ"
              value={asset}
              onChange={e => setAsset(e.target.value.toUpperCase())}
            />
          </div>
          {assetStatus && (
            <div className="col-12">
              <div
                style={{
                  marginTop: 8,
                  padding: 14,
                  borderRadius: 10,
                  background: "rgba(255,255,255,0.03)",
                  border: "1px solid rgba(255,255,255,0.06)",
                }}
              >
                <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 8 }}>{assetStatus.asset}</div>
                <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
                  <span
                    style={{
                      padding: "4px 10px",
                      borderRadius: 999,
                      fontSize: 12,
                      background: assetStatus.openLongRestricted ? "rgba(239,68,68,0.15)" : "rgba(46,189,133,0.1)",
                      color: assetStatus.openLongRestricted ? "#fca5a5" : "#6ee7b7",
                    }}
                  >
                    {assetStatus.openLongRestricted
                      ? `🔴 ${isTr ? "Open-long kısıtlı" : "Open-long restricted"}`
                      : `🟢 ${isTr ? "Long açılabilir" : "Long allowed"}`}
                  </span>
                  <span
                    style={{
                      padding: "4px 10px",
                      borderRadius: 999,
                      fontSize: 12,
                      background: assetStatus.maxCollateralExceeded ? "rgba(239,68,68,0.15)" : "rgba(46,189,133,0.1)",
                      color: assetStatus.maxCollateralExceeded ? "#fca5a5" : "#6ee7b7",
                    }}
                  >
                    {assetStatus.maxCollateralExceeded
                      ? `🔴 ${isTr ? "Teminat limiti aşıldı" : "Max collateral exceeded"}`
                      : `🟢 ${isTr ? "Teminat limiti uygun" : "Collateral OK"}`}
                  </span>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {/* FULL LIST */}
      {mode === "list" && filteredLists && (
        <div className="grid">
          <div className="col-12">
            <label className="label">{isTr ? "Filtrele" : "Filter"}</label>
            <input className="input" placeholder="BTC" value={filter} onChange={e => setFilter(e.target.value)} />
          </div>
          <div className="col-6">
            <label className="label">
              🔴 {isTr ? "Open-long Kısıtlı" : "Open-long Restricted"} ({filteredLists.openLong.length})
            </label>
            <div
              style={{
                maxHeight: 300,
                overflowY: "auto",
                background: "rgba(255,255,255,0.03)",
                border: "1px solid rgba(255,255,255,0.06)",
                borderRadius: 8,
                padding: 10,
                fontSize: 12,
                fontFamily: "monospace",
                lineHeight: 1.6,
              }}
            >
              {filteredLists.openLong.length === 0
                ? (isTr ? "Eşleşme yok." : "No matches.")
                : filteredLists.openLong.map(a => <div key={a}>{a}</div>)}
            </div>
          </div>
          <div className="col-6">
            <label className="label">
              🔴 {isTr ? "Teminat Limiti Aşıldı" : "Max Collateral Exceeded"} ({filteredLists.maxCollat.length})
            </label>
            <div
              style={{
                maxHeight: 300,
                overflowY: "auto",
                background: "rgba(255,255,255,0.03)",
                border: "1px solid rgba(255,255,255,0.06)",
                borderRadius: 8,
                padding: 10,
                fontSize: 12,
                fontFamily: "monospace",
                lineHeight: 1.6,
              }}
            >
              {filteredLists.maxCollat.length === 0
                ? (isTr ? "Eşleşme yok." : "No matches.")
                : filteredLists.maxCollat.map(a => <div key={a}>{a}</div>)}
            </div>
          </div>
        </div>
      )}

      {/* HISTORY */}
      {mode === "history" && (
        <div style={{ marginTop: 10 }}>
          {history.length === 0 ? (
            <div className="helper" style={{ color: "#9aa4b2" }}>
              {isTr
                ? "Henüz kayıt yok. Liste her yenilemede karşılaştırılır ve değişiklikler buraya yazılır."
                : "No entries yet. The list is compared on each refresh and changes are logged here."}
            </div>
          ) : (
            history.map((h, i) => (
              <div
                key={i}
                style={{
                  padding: 10,
                  marginBottom: 8,
                  borderRadius: 8,
                  background: "rgba(255,255,255,0.03)",
                  border: "1px solid rgba(255,255,255,0.06)",
                  fontSize: 12,
                }}
              >
                <div style={{ fontWeight: 700, marginBottom: 6 }}>{fmtTime(h.ts)}</div>
                {h.added.openLong.length > 0 && (
                  <div>🔴 +Open-long: <code>{h.added.openLong.join(", ")}</code></div>
                )}
                {h.removed.openLong.length > 0 && (
                  <div>🟢 -Open-long: <code>{h.removed.openLong.join(", ")}</code></div>
                )}
                {h.added.maxCollateral.length > 0 && (
                  <div>🔴 +MaxCollateral: <code>{h.added.maxCollateral.join(", ")}</code></div>
                )}
                {h.removed.maxCollateral.length > 0 && (
                  <div>🟢 -MaxCollateral: <code>{h.removed.maxCollateral.join(", ")}</code></div>
                )}
              </div>
            ))
          )}
        </div>
      )}

      {error && (
        <div className="helper" style={{ color: "#ff6b6b", marginTop: 10 }}>
          {isTr ? "Hata:" : "Error:"} {error}
        </div>
      )}
    </div>
  );
}

