// src/components/MarginRestrictions.tsx
import React, { useEffect, useMemo, useState } from "react";
import {
  fetchRestricted,
  getApiKey,
  setApiKey,
  getCached,
  getHistory,
  diagnosePair,
  lookupAsset,
  type CachedPayload,
  type Diagnosis,
  type ActionType,
} from "../margin/restrictedAssets";

type Mode = "diagnose" | "asset" | "list" | "history";

function fmtTime(ms: number): string {
  const d = new Date(ms);
  const pad = (n: number) => String(n).padStart(2, "0");
  return (
    `${d.getUTCFullYear()}-${pad(d.getUTCMonth() + 1)}-${pad(d.getUTCDate())} ` +
    `${pad(d.getUTCHours())}:${pad(d.getUTCMinutes())}:${pad(d.getUTCSeconds())} UTC`
  );
}

export default function MarginRestrictions({ lang }: { lang: string }) {
  const isTr = lang === "tr";
  const [mode, setMode] = useState<Mode>("diagnose");
  const [data, setData] = useState<CachedPayload | null>(() => getCached());
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [keyInput, setKeyInput] = useState(() => getApiKey());
  const [keySaved, setKeySaved] = useState(() => Boolean(getApiKey()));
  const [showKey, setShowKey] = useState(false);

  // Diagnose inputs
  const [pair, setPair] = useState("CHZ/USDC");
  const [action, setAction] = useState<ActionType>("short");
  const [diagnosis, setDiagnosis] = useState<Diagnosis | null>(null);

  // Asset-lookup input
  const [asset, setAsset] = useState("CHZ");

  // List filter
  const [filter, setFilter] = useState("");

  const refresh = async (force = false) => {
    setLoading(true);
    setError("");
    try {
      const fresh = await fetchRestricted({ force });
      setData(fresh);
    } catch (e: any) {
      const msg = e?.message || String(e);
      if (msg === "MISSING_API_KEY") {
        setError(isTr ? "Binance API anahtarı gerekli. Aşağıdan girin." : "Binance API key required. Enter it below.");
      } else {
        setError(msg);
      }
    } finally {
      setLoading(false);
    }
  };

  // auto-load on mount if a key is present and cache is empty/stale
  useEffect(() => {
    if (keySaved && (!data || Date.now() - data.fetchedAt > 60_000)) {
      refresh(false);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSaveKey = () => {
    setApiKey(keyInput);
    setKeySaved(Boolean(keyInput.trim()));
    if (keyInput.trim()) refresh(true);
  };

  const handleDiagnose = () => {
    if (!data) {
      setError(isTr ? "Önce veriyi yükleyin." : "Load data first.");
      return;
    }
    setDiagnosis(diagnosePair(pair, action, data));
  };

  const assetStatus = useMemo(() => {
    if (!data || !asset.trim()) return null;
    return lookupAsset(asset, data);
  }, [asset, data]);

  const filteredLists = useMemo(() => {
    if (!data) return null;
    const f = filter.trim().toUpperCase();
    const openLong = f
      ? data.openLongRestrictedAsset.filter(a => a.includes(f))
      : data.openLongRestrictedAsset;
    const maxCollat = f
      ? data.maxCollateralExceededAsset.filter(a => a.includes(f))
      : data.maxCollateralExceededAsset;
    return { openLong, maxCollat };
  }, [data, filter]);

  const history = useMemo(() => getHistory().slice().reverse(), [data]);

  const copyReply = async () => {
    if (!diagnosis?.customerReply) return;
    try {
      await navigator.clipboard.writeText(diagnosis.customerReply);
    } catch {
      /* ignore */
    }
  };

  return (
    <div className="panel">
      <h3>{isTr ? "Margin Kısıtlamaları" : "Margin Restrictions"}</h3>

      {/* API key setup */}
      {!keySaved && (
        <div
          style={{
            background: "rgba(239,68,68,0.08)",
            border: "1px dashed rgba(239,68,68,0.5)",
            padding: 12,
            borderRadius: 8,
            marginBottom: 14,
            fontSize: 13,
            color: "#fca5a5",
          }}
        >
          {isTr
            ? "Bu özellik Binance API anahtarı gerektirir (MARKET_DATA). Anahtar sadece bu tarayıcıda localStorage'da saklanır, kaynak kodda bulunmaz."
            : "This feature requires a Binance API key (MARKET_DATA endpoint). The key is stored only in your browser's localStorage and is never committed to source code."}
        </div>
      )}

      <div className="grid" style={{ marginBottom: 10 }}>
        <div className="col-12">
          <label className="label">{isTr ? "API Anahtarı (yalnızca bu tarayıcıda saklanır)" : "API Key (stored in this browser only)"}</label>
          <div style={{ display: "flex", gap: 6 }}>
            <input
              className="input"
              type={showKey ? "text" : "password"}
              placeholder="X-MBX-APIKEY"
              value={keyInput}
              onChange={e => setKeyInput(e.target.value)}
              style={{ flex: 1 }}
            />
