          <span>{isTr ? "Varlık Ara" : "Asset Lookup"}</span>
        </div>
        <div className={`option-card ${mode === "list" ? "active" : ""}`} onClick={() => setMode("list")}>
          <span>{isTr ? "Tam Liste" : "Full List"}</span>
        </div>
        <div className={`option-card ${mode === "history" ? "active" : ""}`} onClick={() => setMode("history")}>
          <span>{isTr ? "Değişim Günlüğü" : "Changes"}</span>
        </div>
      </div>

      {/* DIAGNOSE MODE */}
      {mode === "diagnose" && (
        <div className="grid">
          <div className="col-6">
            <label className="label">{isTr ? "İşlem Çifti" : "Trading Pair"}</label>
            <input
              className="input"
              placeholder="CHZ/USDC"
